insert into public.eps_questions (exam_id, order_no, question_type, section, option_type, question_text, content, content_image, options, option_images, audio_script, audio_options, audio_hint, explanation, correct_answer)
values ('11111111-de02-4000-8000-000000000002'::uuid, 16, 'reading', 'reading', 'text', '다음은 무엇에 대한 설명입니까?', '한국 생활에서 화재나 응급 환자가 생겼을 때는 119번에 전화를 하면 됩니다. 그 외에도 범죄를 신고할 때는 112번, 전화번호를 알고 싶을 때는 114번, 일기예보가 궁금할 때는 131번을 이용하면 됩니다. 도움이 필요할 때 언제든지 이런 전화번호들을 이용할 수 있습니다.', NULL, '["전화의 장점과 거는 방법","외국인들을 위한 상담 안내","알고 있으면 유용한 전화번호","환자가 생겼을 때 대처 방법"]'::jsonb, NULL, NULL, NULL, NULL, 'Đoạn văn liệt kê số điện thoại hữu ích (119/112/114/131) → chủ đề: 알고 있으면 유용한 전화번호.', 3)
on conflict (exam_id, order_no) do update set
  question_type = excluded.question_type,
  section = excluded.section,
  option_type = excluded.option_type,
  question_text = excluded.question_text,
  content = excluded.content,
  content_image = excluded.content_image,
  options = excluded.options,
  option_images = excluded.option_images,
  audio_script = excluded.audio_script,
  audio_options = excluded.audio_options,
  audio_hint = excluded.audio_hint,
