  correct_answer = excluded.correct_answer;
insert into public.eps_questions (exam_id, order_no, question_type, section, option_type, question_text, content, content_image, options, option_images, audio_script, audio_options, audio_hint, explanation, correct_answer)
values ('11111111-de02-4000-8000-000000000002'::uuid, 17, 'reading', 'reading', 'text', '다음 글을 읽고 내용과 같은 것을 고르십시오.', '스마트팜은 생산성을 향상시키기 위하여 정보통신기술을 활용하는 농업 방식입니다. 빅데이터와 인공지능 기술을 활용하여 농작물의 성장 조건을 최적화하기 때문에 노동력을 줄이는 데도 도움을 줍니다. 한국에서는 스마트팜을 활용하여 과일, 쌈채소뿐만 아니라 허브류 재배도 하고 있습니다. 그리고 정부에서는 스마트팜 보급과 발전을 위해 다양한 정책으로 지원하고 있습니다.', NULL, '["스마트팜은 정부의 지원 없이 운영되고 있습니다.","스마트팜 방식을 이용하면 사람이 해야 할 일이 많아집니다.","한국에서는 스마트팜 방식으로 쌈채소를 재배하지 않습니다.","스마트팜은 농작물의 성장을 위해 인공지능 기술을 활용합니다."]'::jsonb, NULL, NULL, NULL, NULL, 'Đáp án ④ đúng: ''Nông nghiệp thông minh sử dụng AI để tối ưu điều kiện sinh trưởng''. ①②③ đều sai theo nội dung.', 4)
